/**
 * Pick the most relevant subset of the RAG list for a given reading profile —
 * a lightweight "retrieval" step so ARIA's recommendation prompts stay short
 * and grounded in real, popular titles instead of the model's raw memory.
 *
 * @param {{genres?: string[], favorite?: string}} profile
 * @param {number} limit  max number of books to return
 */
export function pickBooksForProfile(profile, limit = 18) {
  const genres = (profile?.genres ?? []).map(g => String(g).toLowerCase());
  if (!genres.length) {
    // No profile yet — return a broad, popular cross-section.
    return shuffle(BOOKLIST).slice(0, limit);
  }
  const scored = BOOKLIST.map(book => {
    const overlap = book.genres.filter(g => genres.includes(g)).length;
    return { book, score: overlap + Math.random() * 0.5 }; // jitter avoids same-order ruts
  });
  scored.sort((a, b) => b.score - a.score);
  const top = scored.filter(s => s.score >= 1).map(s => s.book);
  if (top.length >= limit) return top.slice(0, limit);
  // Backfill with a random sample of the rest so the list still feels fresh.
  const rest = shuffle(BOOKLIST.filter(b => !top.includes(b)));
  return [...top, ...rest].slice(0, limit);
}

/** Render a compact "Title by Author — blurb [genre, genre]" block for prompts. */
export function formatBooksForPrompt(books) {
  return books.map(b => `• ${b.title} by ${b.author} — ${b.blurb} [${b.genres.join(', ')}]`).join('\n');
}

